{"stream":"Step 3/4 : COPY hello.sh /test"}
{"stream":"\n"}
{"errorDetail":{"message":"COPY failed: file not found in build context or excluded by .dockerignore: stat hello.sh: file does not exist"},"error":"COPY failed: file not found in build context or excluded by .dockerignore: stat hello.sh: file does not exist"}
